CREATE TABLE IF NOT EXISTS `fortress` (
  `id` int(11) NOT NULL DEFAULT 0,
  `name` varchar(45) NOT NULL,
  `side` enum('NEUTRAL','LIGHT','DARK') DEFAULT 'NEUTRAL' NOT NULL,
  `is_farm` enum('true','false') DEFAULT 'false' NOT NULL,
  `state` tinyint(3) unsigned NOT NULL DEFAULT 0,
  `castle_id` int(11) NOT NULL DEFAULT 0,
  `last_siege_date` bigint(20) NOT NULL DEFAULT 0,
  `own_date` bigint(20) NOT NULL DEFAULT 0,
  `siege_date` bigint(20) NOT NULL DEFAULT 0,
  `supply_count` bigint(20) NOT NULL DEFAULT 0,
  `facility_0` int(11) NOT NULL DEFAULT 0,
  `facility_1` int(11) NOT NULL DEFAULT 0,
  `facility_2` int(11) NOT NULL DEFAULT 0,
  `facility_3` int(11) NOT NULL DEFAULT 0,
  `facility_4` int(11) NOT NULL DEFAULT 0,
  `cycle` int(11) NOT NULL DEFAULT 0,
  `reward_count` int(11) NOT NULL DEFAULT 0,
  `paid_cycle` int(11) NOT NULL DEFAULT 0,
  `epaulettes` bigint(20) unsigned NOT NULL DEFAULT 0,
  `siegeDate` bigint(20) unsigned NOT NULL DEFAULT 0,
  `lastOwnedTime` bigint(20) unsigned NOT NULL DEFAULT 0,
  `owner` int(11) NOT NULL DEFAULT 0,
  `fortType` tinyint(1) NOT NULL DEFAULT 0,
  `castleId` int(11) NOT NULL DEFAULT 0,
  `supplyLvL` tinyint(2) NOT NULL DEFAULT 0,
  PRIMARY KEY (`id`),
  KEY `owner` (`owner`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;

